#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=2000005;
int n,m,dfn[N],low[N],vis[N],siz[N],id[N],cnt,cnt2;
stack<int> st;
vector<int> g[N];
void tarjan(int u)
{
	low[u]=dfn[u]=++cnt;
	st.push(u);
	vis[u]=1;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(!dfn[v])
		{
			tarjan(v);
			low[u]=min(low[u],low[v]);
		}
		else if(vis[v])
		{
			low[u]=min(low[u],dfn[v]);
		}
	}
	if(low[u]==dfn[u])
	{
		cnt2++;
		int v;
		while(v=st.top())
		{
			vis[v]=0;
			id[v]=cnt2;
			siz[cnt2]++;
			st.pop();
			if(v==u) break;
		}
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	for(int i=1;i<=m;i++)
	{
		int u,u2,v,v2;
		cin>>u>>u2>>v>>v2;
		u2--;
		v2--;
		v=v*2+v2;
		u=u*2+u2;
		g[(v%2==0)?(v-1):(v+1)].push_back(u);
		g[(u%2==0)?(u-1):(u+1)].push_back(v);
	}
	for(int i=1;i<=2*n;i++)
	{
		if(!dfn[i])
		{
			tarjan(i);	
		}
	}
	for(int i=1;i<=2*n;i+=2)
	{
		if(id[i]==id[i+1])
		{
			cout<<"IMPOSSIBLE";
			return 0;
		}
	}
	cout<<"POSSIBLE\n";
	for(int i=1;i<=2*n;i+=2)
	{
		if(id[i]<id[i+1])
		{
			cout<<0<<' ';
		}
		else
		{
			cout<<1<<' ';
		}
	}
	return 0;
}
